def count_three_char_palindromes(s):
    count = 0
    freq = {}
    for ch in s:
        if ch in freq:
            freq[ch] += 1
        else:
            freq[ch] = 1
    for value in freq.values():
        count += value * (value - 1) // 2
    return count
```


