public int countThreeCharPalindromes(String s) {
    int count = 0;
    HashMap<Character, Integer> freq = new HashMap<>();
    for (char ch : s.toCharArray()) {
        freq.put(ch, freq.getOrDefault(ch, 0) + 1);
    }
    for (int value : freq.values()) {
        count += value * (value - 1) / 2;
    }
    return count;
}
```


